const entry = $input.first().json;

if (!entry.messages || entry.messages.length === 0) {
  return [];
}

const msg = entry.messages[0];
const contact = entry.contacts?.[0];

let messageText = '';
let messageType = msg.type;

if (msg.type === 'text') {
  messageText = msg.text.body;
} else if (msg.type === 'interactive') {
  if (msg.interactive.type === 'button_reply') {
    messageText = `[BUTTON:${msg.interactive.button_reply.id}] ${msg.interactive.button_reply.title}`;
  } else if (msg.interactive.type === 'list_reply') {
    messageText = `[LIST:${msg.interactive.list_reply.id}] ${msg.interactive.list_reply.title}`;
  }
} else if (msg.type === 'image' || msg.type === 'audio' || msg.type === 'video' || msg.type === 'document') {
  messageText = '[Media file - please send text message]';
}

if (!messageText) {
  return [];
}

return [{
  json: {
    customer_phone: msg.from,
    customer_name: contact?.profile?.name || 'Customer',
    message_text: messageText,
    message_type: messageType,
    phone_number_id: entry.metadata.phone_number_id
  }
}];

const msg = $input.first().json;
const text = (msg.message_text || '').trim();
const lower = text.toLowerCase();

const MENU_IMAGE_URL = 'https://drive.google.com/uc?export=view&id=16-FMyCT20h2azFqlbEqaYxe7E2Dkp2bs';
const MAIN_BUTTONS = [
  { id: 'menu', title: 'Меню' },
  { id: 'reserve', title: 'Забронировать' },
  { id: 'order', title: 'Заказать' }
];

function makeOutput(reply, buttons, intent, image_url) {
  const obj = { reply, buttons, intent: intent || 'general', save_data: null };
  if (image_url) obj.image_url = image_url;
  return JSON.stringify(obj);
}

let output = null;
const cleaned = lower.replace(/[\s!.,?]+$/g, '');

// 1. GREETINGS
const greetings = [
  'привет', 'здравствуйте', 'здравствуй',
  'добрый день', 'добрый', 'доброе утро', 'добрый вечер',
  'доброго дня', 'доброго утра', 'доброго вечера',
  'hi', 'hello', 'hey', 'start',
  'старт', 'начать', 'хай', 'ку',
  'салам', 'сәлем', 'сәлеметсіз бе'
];

if (greetings.includes(cleaned)) {
  output = makeOutput(
    'Добро пожаловать в ресторан West and East🏩!\n\nЯ помогу вам с меню, заказом или бронированием столика.\n\nВыберите действие:',
    MAIN_BUTTONS,
    'greeting'
  );
}
// 2. MENU - button OR text
else if (text.startsWith('[BUTTON:menu]') || cleaned === 'меню') {
  output = makeOutput(
    'Полное меню ресторана West and East:',
    [{ id: 'order', title: 'Заказать' }, { id: 'reserve', title: 'Забронировать' }],
    'menu',
    MENU_IMAGE_URL
  );
}
// 3. CANCEL
else if (text.startsWith('[BUTTON:cancel]')) {
  output = makeOutput('Действие отменено. Чем могу помочь?', MAIN_BUTTONS, 'farewell');
}
// 4. HELP
else if (text.startsWith('[BUTTON:help]')) {
  output = makeOutput(
    'Я умею:\n- Показывать меню\n- Принять заказ\n- Забронировать столик',
    MAIN_BUTTONS,
    'question'
  );
}
// 5. Everything else -> AI Agent

return [{
  json: {
    ...msg,
    output: output,
    has_static: output !== null
  }
}];

const raw = $input.first().json.output;
const customerPhone = $('Extract Message').first().json.customer_phone;
const customerName = $('Extract Message').first().json.customer_name;
const phoneNumberId = $('Extract Message').first().json.phone_number_id;

const ALLOWED_RECIPIENT = 'YOUR_WHATSAPP_NUMBER';

let data;
try {
  let str = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const jsonMatch = str.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    data = JSON.parse(jsonMatch[0]);
  } else {
    data = { reply: str, intent: 'general', buttons: [], save_data: null };
  }
  if (data.output && typeof data.output === 'object') {
    data = data.output;
  } else if (data.output && typeof data.output === 'string') {
    try { data = JSON.parse(data.output); } catch(e) {}
  }
} catch(e) {
  data = {
    reply: String(raw || 'Извините, произошла ошибка.'),
    intent: 'general',
    buttons: [],
    save_data: null
  };
}

data.reply = data.reply || 'Чем могу помочь?';
data.intent = data.intent || 'general';
data.buttons = Array.isArray(data.buttons) ? data.buttons : [];
data.save_data = data.save_data || null;

const validButtons = data.buttons
  .filter(b => b && b.id && b.title)
  .slice(0, 3);

const baseFields = {
  phone_number_id: phoneNumberId,
  intent: data.intent,
  save_data: data.save_data,
  has_save_data: !!data.save_data,
  customer_phone: customerPhone,
  customer_name: customerName
};

// If image_url: single item with image payload + buttons stored separately
if (data.image_url) {
  const imagePayload = {
    messaging_product: 'whatsapp',
    to: ALLOWED_RECIPIENT,
    type: 'image',
    image: {
      link: data.image_url,
      caption: data.reply.substring(0, 1024)
    }
  };

  let buttonsPayload = null;
  if (validButtons.length > 0) {
    buttonsPayload = {
      messaging_product: 'whatsapp',
      to: ALLOWED_RECIPIENT,
      type: 'interactive',
      interactive: {
        type: 'button',
        body: { text: 'Выберите:' },
        action: {
          buttons: validButtons.map(b => ({
            type: 'reply',
            reply: {
              id: String(b.id).substring(0, 256),
              title: String(b.title).substring(0, 20)
            }
          }))
        }
      }
    };
  }

  return [{
    json: {
      wa_payload: imagePayload,
      wa_buttons_payload: buttonsPayload,
      ...baseFields
    }
  }];
}

// Standard flow: text or interactive
const payload = {
  messaging_product: 'whatsapp',
  to: ALLOWED_RECIPIENT,
};

if (validButtons.length > 0) {
  payload.type = 'interactive';
  payload.interactive = {
    type: 'button',
    body: { text: data.reply.substring(0, 1024) },
    action: {
      buttons: validButtons.map(b => ({
        type: 'reply',
        reply: {
          id: String(b.id).substring(0, 256),
          title: String(b.title).substring(0, 20)
        }
      }))
    }
  };
} else {
  payload.type = 'text';
  payload.text = { body: data.reply.substring(0, 4096) };
}

return [{
  json: {
    wa_payload: payload,
    wa_buttons_payload: null,
    ...baseFields
  }
}];

const parseResponse = $('Parse Response').first().json;
const buttonsPayload = parseResponse.wa_buttons_payload;

if (!buttonsPayload) {
  return [];
}

// Wait 4 seconds for WhatsApp to deliver the image
await new Promise(resolve => setTimeout(resolve, 4000));

return [{
  json: {
    wa_payload: buttonsPayload,
    phone_number_id: parseResponse.phone_number_id
  }
}];
